CREATE TABLE exhibitor_relationships (id uuid PRIMARY KEY DEFAULT concourse.uuid_generate_v7(), event_exhibitor_id uuid NOT NULL REFERENCES event_exhibitors(id) ON DELETE CASCADE, attendee_user_id uuid NOT NULL REFERENCES users(id) ON DELETE CASCADE, status text NOT NULL DEFAULT 'active', first_interaction_at timestamptz NOT NULL DEFAULT now(), latest_interaction_at timestamptz NOT NULL DEFAULT now(), interaction_count integer NOT NULL DEFAULT 0, has_potential_duplicate boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT exhibitor_relationships_status_check CHECK (status IN ('active','archived'))); CREATE UNIQUE INDEX exhibitor_relationships_exhibitor_attendee_key ON exhibitor_relationships(event_exhibitor_id,attendee_user_id); CREATE INDEX exhibitor_relationships_exhibitor_updated_idx ON exhibitor_relationships(event_exhibitor_id,updated_at);
CREATE TABLE exhibitor_relationship_notes (id uuid PRIMARY KEY DEFAULT concourse.uuid_generate_v7(), relationship_id uuid NOT NULL REFERENCES exhibitor_relationships(id) ON DELETE CASCADE, body text NOT NULL, status text NOT NULL DEFAULT 'active', created_by_user_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now(), CONSTRAINT exhibitor_relationship_notes_status_check CHECK (status IN ('active','archived'))); CREATE INDEX exhibitor_relationship_notes_relationship_idx ON exhibitor_relationship_notes(relationship_id,created_at);
INSERT INTO exhibitor_relationships(event_exhibitor_id,attendee_user_id) SELECT DISTINCT event_exhibitor_id,attendee_user_id FROM lead_submissions WHERE attendee_user_id IS NOT NULL ON CONFLICT DO NOTHING;
ALTER TABLE lead_submissions ADD COLUMN relationship_id uuid REFERENCES exhibitor_relationships(id) ON DELETE RESTRICT; UPDATE lead_submissions submission SET relationship_id=relationship.id FROM exhibitor_relationships relationship WHERE relationship.event_exhibitor_id=submission.event_exhibitor_id AND relationship.attendee_user_id=submission.attendee_user_id; CREATE INDEX lead_submissions_relationship_submitted_at_idx ON lead_submissions(relationship_id,submitted_at);
GRANT SELECT,INSERT,UPDATE ON exhibitor_relationships,exhibitor_relationship_notes TO app_tenant; GRANT ALL PRIVILEGES ON exhibitor_relationships,exhibitor_relationship_notes TO app_platform;
ALTER TABLE exhibitor_relationships ENABLE ROW LEVEL SECURITY; ALTER TABLE exhibitor_relationships FORCE ROW LEVEL SECURITY; CREATE POLICY tenant_isolation ON exhibitor_relationships USING(event_exhibitor_id IN (SELECT id FROM event_exhibitors WHERE organization_id=current_setting('app.current_org_id',true)::uuid)) WITH CHECK(event_exhibitor_id IN (SELECT id FROM event_exhibitors WHERE organization_id=current_setting('app.current_org_id',true)::uuid));
ALTER TABLE exhibitor_relationship_notes ENABLE ROW LEVEL SECURITY; ALTER TABLE exhibitor_relationship_notes FORCE ROW LEVEL SECURITY; CREATE POLICY tenant_isolation ON exhibitor_relationship_notes USING(relationship_id IN (SELECT id FROM exhibitor_relationships)) WITH CHECK(relationship_id IN (SELECT id FROM exhibitor_relationships));
